// Extrai e valida os dados da requisição
const body = $input.first().json.body || $input.first().json;

const question = (body.question || '').trim();
const metadata = body.metadata || { tables: [], columns: [], measures: [] };
const conversationHistory = Array.isArray(body.conversationHistory) ? body.conversationHistory : [];
const todayDate = body.todayDate || new Date().toLocaleDateString('pt-BR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

if (!question) {
  throw new Error('Pergunta não pode ser vazia');
}

// Constrói o schema do dataset para o prompt
const schemaLines = [];
const tables = (metadata.tables || []).filter(t => !t.isHidden);
const columns = (metadata.columns || []).filter(c => !c.isHidden);
const measures = (metadata.measures || []).filter(m => !m.isHidden);

// Junta tabelas explícitas + tabelas implícitas de colunas/medidas
const allTableNames = new Set([
  ...tables.map(t => t.name),
  ...columns.map(c => c.tableName),
  ...measures.map(m => m.tableName)
]);

for (const tableName of allTableNames) {
  const cols = columns
    .filter(c => c.tableName === tableName)
    .map(c => `      - ${c.columnName} (${c.dataType})`);
  const meas = measures
    .filter(m => m.tableName === tableName)
    .map(m => `      - [${m.measureName}]`);

  schemaLines.push(`  Tabela: '${tableName}'`);
  if (cols.length > 0) {
    schemaLines.push('    Colunas:');
    schemaLines.push(...cols);
  }
  if (meas.length > 0) {
    schemaLines.push('    Medidas:');
    schemaLines.push(...meas);
  }
}

const schemaContext = schemaLines.join('\n') || '(Nenhum schema disponível)';

// Monta as mensagens para OpenAI
const systemPrompt = `Você é um especialista em Power BI e DAX. Seu papel é interpretar perguntas em linguagem natural e gerar consultas DAX válidas.

DATA DE HOJE: ${todayDate}

=== SCHEMA DO DATASET ===
${schemaContext}
=== FIM DO SCHEMA ===

REGRAS OBRIGATÓRIAS:
1. Use APENAS tabelas, colunas e medidas que existem no schema acima.
2. Formato de coluna: 'NomeDaTabela'[NomeDaColuna]
3. Formato de medida: [NomeDaMedida]
4. Para filtros de data, use TODAY(), DATE(ano, mes, dia) ou DATEVALUE().
5. Sempre envolva medidas com COALESCE([Medida], 0).
6. Para totais: EVALUATE ROW("Nome", COALESCE(CALCULATE([Medida]), 0))
7. Para agrupamentos: EVALUATE TOPN(100, SUMMARIZECOLUMNS(...), [Medida], DESC)
8. Para listagens: EVALUATE TOPN(100, SELECTCOLUMNS('Tabela', ...), ...)
9. Confidence: high=pergunta clara; medium=interpretação razoável; low=ambíguo.

RETORNE APENAS JSON PURO (sem markdown, sem backticks):
{
  "selectedColumns": [{"tableName": "string", "columnName": "string"}],
  "selectedMeasures": [{"tableName": "string", "measureName": "string"}],
  "filters": [{"tableName": "string", "columnName": "string", "operator": "eq|neq|gt|lt|gte|lte|contains|startswith", "value": "string", "valueTo": "", "dataType": "string"}],
  "daxQuery": "EVALUATE ...",
  "explanation": "Explicação em português",
  "confidence": "high|medium|low"
}`;

const messages = [
  { role: 'system', content: systemPrompt },
  // Inclui últimas 6 mensagens do histórico
  ...conversationHistory.slice(-6).map(m => ({ role: m.role, content: m.content })),
  { role: 'user', content: question }
];

return {
  question,
  messages,
  metadata,
  todayDate,
  hasSchema: allTableNames.size > 0
};

// Valida e parseia a resposta da OpenAI
const rawResponse = $input.first().json.content || $input.first().json.message?.content || '';
const metadataNode = $('Preparar Prompt e Contexto').first().json;
const metadata = metadataNode.metadata || { columns: [], measures: [] };

let plan;
try {
  const cleaned = rawResponse
    .trim()
    .replace(/^```(?:json)?\n?/i, '')
    .replace(/\n?```$/i, '')
    .trim();
  plan = JSON.parse(cleaned);
} catch (e) {
  return {
    valid: false,
    error: 'Resposta da IA não é JSON válido: ' + e.message,
    rawResponse
  };
}

if (!plan.daxQuery || !String(plan.daxQuery).trim().toUpperCase().startsWith('EVALUATE')) {
  return {
    valid: false,
    error: 'Query DAX inválida: deve começar com EVALUATE',
    rawResponse
  };
}

// Validação de colunas/medidas contra o schema
const columnSet = new Set(
  (metadata.columns || []).map(c => `${c.tableName}::${c.columnName}`)
);
const measureSet = new Set(
  (metadata.measures || []).map(m => m.measureName)
);

const errors = [];

for (const col of (plan.selectedColumns || [])) {
  if (col.tableName && col.columnName && !columnSet.has(`${col.tableName}::${col.columnName}`)) {
    errors.push(`Coluna inexistente: '${col.tableName}'[${col.columnName}]`);
  }
}

for (const meas of (plan.selectedMeasures || [])) {
  if (meas.measureName && !measureSet.has(meas.measureName)) {
    errors.push(`Medida inexistente: [${meas.measureName}]`);
  }
}

if (errors.length > 0 && metadata.columns?.length > 0) {
  return {
    valid: false,
    error: errors.join('; '),
    plan,
    rawResponse
  };
}

return {
  valid: true,
  plan,
  rawResponse
};

// Query válida - formata resposta de sucesso
const validationResult = $input.first().json;
const plan = validationResult.plan;

return {
  success: true,
  selectedColumns: plan.selectedColumns || [],
  selectedMeasures: plan.selectedMeasures || [],
  filters: plan.filters || [],
  daxQuery: plan.daxQuery,
  explanation: plan.explanation || 'Consulta gerada com sucesso.',
  confidence: plan.confidence || 'medium'
};

// Query inválida - retorna erro com detalhes
const validationResult = $input.first().json;

return {
  success: false,
  error: validationResult.error || 'Não foi possível gerar uma query válida',
  explanation: `Não consegui interpretar sua pergunta com precisão. Erro: ${validationResult.error}`,
  confidence: 'low',
  daxQuery: validationResult.plan?.daxQuery || null,
  selectedColumns: [],
  selectedMeasures: [],
  filters: []
};
